// Herramienta: calcular_eoq
// Implementa el Modelo de Wilson (EOQ)

let params;
try {
  params = JSON.parse(query);
} catch (e) {
  return 'Error al parsear parámetros. Enviá un JSON válido. Ejemplo: {"D": 1200, "K": 4000, "c1": 800, "T": 1}';
}

const D  = parseFloat(params.D);
const K  = parseFloat(params.K);
const c1 = parseFloat(params.c1);
const T  = parseFloat(params.T !== undefined && params.T !== '' ? params.T : 1);

// Validaciones de seguridad
if ([D, K, c1, T].some(v => isNaN(v) || v <= 0)) {
  return JSON.stringify({
    error: true,
    mensaje: 'Todos los parámetros deben ser números positivos. D>0, K>0, c1>0, T>0.'
  });
}

// Fórmula de Wilson: q0 = sqrt(2*K*D / (T*c1))
const q0_exacto = Math.sqrt((2 * K * D) / (T * c1));
const q0 = Math.round(q0_exacto);

// Costo total con EOQ exacto
const costo_pedido    = (D / q0_exacto) * K;
const costo_mantener  = (q0_exacto / 2) * T * c1;
const CTE_exacto      = costo_pedido + costo_mantener;

// Costo total con EOQ redondeado
const CTE_redondeado = (D / q0) * K + (q0 / 2) * T * c1;

// Métricas derivadas
const N = D / q0_exacto;          // número de pedidos por período
const t = T / N;                   // tiempo entre pedidos (en unidades de T)
const t_dias = Math.round(t * 365); // tiempo en días (asume T en años)

return JSON.stringify({
  q0_exacto:              parseFloat(q0_exacto.toFixed(2)),
  q0_redondeado:          q0,
  CTE_exacto:             parseFloat(CTE_exacto.toFixed(2)),
  CTE_redondeado:         parseFloat(CTE_redondeado.toFixed(2)),
  costo_pedido_periodo:   parseFloat(costo_pedido.toFixed(2)),
  costo_mantener_periodo: parseFloat(costo_mantener.toFixed(2)),
  numero_pedidos:         parseFloat(N.toFixed(2)),
  tiempo_entre_pedidos:   parseFloat(t.toFixed(4)),
  tiempo_entre_pedidos_dias: t_dias,
  parametros_usados:      { D, K, c1, T },
  verificacion_formula:   `q0 = sqrt((2 * ${K} * ${D}) / (${T} * ${c1})) = sqrt(${(2*K*D/(T*c1)).toFixed(2)}) = ${q0_exacto.toFixed(2)}`
});

// Herramienta: validar_parametros

let params;
try {
  params = JSON.parse(query);
} catch (e) {
  return JSON.stringify({
    valido: false,
    errores: ['No se pudo parsear el JSON de parámetros'],
    mensaje: 'Error de formato. Enviá: {"D": valor, "K": valor, "c1": valor, "T": valor}'
  });
}

const errores = [];
const campos = [
  { clave: 'D',  nombre: 'Demanda (D)' },
  { clave: 'K',  nombre: 'Costo fijo por pedido (K)' },
  { clave: 'c1', nombre: 'Costo de mantenimiento (c1)' }
];

for (const { clave, nombre } of campos) {
  const valor = params[clave];
  if (valor === undefined || valor === null || valor === '') {
    errores.push(`${nombre}: parámetro requerido, no fue proporcionado`);
  } else if (isNaN(parseFloat(valor))) {
    errores.push(`${nombre}: debe ser un número (recibido: "${valor}")`);
  } else if (parseFloat(valor) <= 0) {
    errores.push(`${nombre}: debe ser mayor que 0 (recibido: ${valor})`);
  }
}

// T es opcional (default 1)
if (params.T !== undefined && params.T !== null && params.T !== '') {
  const T = parseFloat(params.T);
  if (isNaN(T) || T <= 0) {
    errores.push(`Duración del período (T): debe ser un número positivo (recibido: ${params.T})`);
  }
}

if (errores.length > 0) {
  return JSON.stringify({
    valido: false,
    errores,
    mensaje: `Parámetros inválidos:\n${errores.map(e => '• ' + e).join('\n')}\nCorregí estos valores e intentá nuevamente.`
  });
}

return JSON.stringify({
  valido: true,
  mensaje: 'Todos los parámetros son válidos. Procediendo al cálculo.',
  parametros_validados: {
    D: parseFloat(params.D),
    K: parseFloat(params.K),
    c1: parseFloat(params.c1),
    T: parseFloat(params.T !== undefined && params.T !== '' ? params.T : 1)
  }
});

// Herramienta: explicar_concepto

let params;
try {
  params = JSON.parse(query);
} catch (e) {
  params = { concepto: query.toLowerCase().trim() };
}

const concepto = (params.concepto || '').toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, ''); // quitar acentos

const base = {
  eoq: `## Modelo EOQ (Cantidad Económica de Pedido)
También conocido como **Modelo de Wilson** o Modelo I. Es un modelo determinístico estático que calcula el tamaño óptimo del lote de pedido que **minimiza el Costo Total Esperado (CTE)**.

Equilibra dos fuerzas económicas contrapuestas:
- 📦 **Costo de pedir** (disminuye si pedimos más cantidad cada vez)
- 🏭 **Costo de mantener** (aumenta si pedimos más cantidad cada vez)

El óptimo está exactamente donde ambas curvas se intersectan.`,

  demanda: `## Demanda (D)
Cantidad total de unidades requeridas durante el período de análisis T.

**Supuesto clave**: en el EOQ la demanda es **constante y conocida** (determinística). No hay variabilidad.

Ejemplo: D = 1.200 unidades/año (la ferretería vende 1.200 bolsas de cemento por año).`,

  costo_pedido: `## Costo de Pedido / Preparación (K)
Costo **fijo** asociado a emitir una orden de compra, **independiente del tamaño del lote**.

Incluye: gastos administrativos, comunicación, recepción, logística.

Ejemplo: K = $4.000 por pedido (sin importar si se piden 10 o 1.000 unidades).`,

  costo_mantenimiento: `## Costo de Mantenimiento (c1)
Costo de mantener **una unidad** almacenada durante **una unidad de tiempo**.

Incluye: alquiler del depósito, seguros, deterioro, capital inmovilizado.

Ejemplo: c1 = $800/unidad/año (mantener una bolsa de cemento un año cuesta $800).`,

  cte: `## Costo Total Esperado (CTE)
Función que el modelo **minimiza**:

> **CTE = (D/q) × K + (q/2) × T × c1**

Donde:
- **(D/q) × K** = Costo total de emisión de órdenes en el período
- **(q/2) × T × c1** = Costo total de almacenamiento en el período
- q = cantidad pedida por orden

Cada término baja cuando el otro sube: ese equilibrio define el óptimo.`,

  supuestos: `## Supuestos del Modelo EOQ/Wilson
1. **Demanda constante y conocida** (sin variabilidad)
2. **Plazo de entrega nulo** (o constante y conocido, caso avanzado)
3. **No se permiten faltantes** (ruptura de stock = no permitida)
4. **Costo unitario constante** (sin descuentos por volumen)
5. **Horizonte de planificación continuo** (el modelo se repite indefinidamente)
6. **Un solo producto** en la versión básica`,

  formula: `## Fórmula de Wilson (Lote Óptimo)

> **q₀ = √( 2 × K × D / (T × c1) )**

Parámetros:
| Símbolo | Significado |
|---------|-------------|
| D | Demanda total del período |
| K | Costo fijo por pedido |
| c1 | Costo de mantenimiento por unidad/período |
| T | Duración del período (default: 1 año) |

Esta fórmula se obtiene derivando la función CTE respecto a q e igualando a cero: dCTE/dq = 0.`,

  restricciones: `## Restricciones del Modelo

**A. No negatividad** (condición obligatoria de PL):
> q ≥ 0 y N ≥ 0

**B. Positividad de parámetros**:
> D > 0, K > 0, c1 > 0, T > 0

**C. Capacidad de almacenamiento** (restricción operativa):
> ∑(sᵢ × Nᵢₜ) ≤ S

Donde sᵢ = superficie/volumen que ocupa una unidad del producto i, y S = capacidad total del depósito. Si q₀ > capacidad máxima, el lote óptimo queda restringido por el espacio físico.`
};

const claves = Object.keys(base);
const match = claves.find(k => concepto.includes(k)) ||
              claves.find(k => k.includes(concepto));

if (base[concepto]) {
  return base[concepto];
} else if (match) {
  return base[match];
} else {
  return `Concepto "${concepto}" no encontrado.\n\nConceptos disponibles:\n${claves.map(k => '• ' + k).join('\n')}\n\n¿Sobre cuál querés aprender?`;
}

// Herramienta: modo_practica

let params;
try {
  params = JSON.parse(query);
} catch (e) {
  params = { ejercicio: 1 };
}

const num = parseInt(params.ejercicio) || 1;

const ejercicios = [
  {
    id: 1,
    contexto: 'Ferretería local (bolsas de cemento)',
    enunciado: 'Una ferretería ubicada en Resistencia vende **1.200 bolsas de cemento** por año.\n\n' +
               '- Costo de emitir un pedido: **$4.000** (gastos administrativos, recepción y logística)\n' +
               '- Costo de mantener una bolsa en inventario: **$800/año**\n' +
               '- Horizonte de planificación: T = 1 año\n\n' +
               '**¿Cuál es la cantidad óptima de pedido (q₀)?**\n' +
               '*(Redondeá el resultado al entero más cercano)*',
    datos: { D: 1200, K: 4000, c1: 800, T: 1 },
    solucion: {
      q0_exacto: 109.54,
      q0_redondeado: 110,
      CTE: 87636.36,
      paso_a_paso: 'q0 = sqrt((2 × 4000 × 1200) / (1 × 800)) = sqrt(9.600.000 / 800) = sqrt(12.000) ≈ 109,54 ≈ **110 unidades**'
    },
    pista: 'Aplicá la Fórmula de Wilson: q₀ = √(2 × K × D / (T × c1)). Con D=1200, K=4000, c1=800, T=1... el numerador es 2×4000×1200 = 9.600.000'
  },
  {
    id: 2,
    contexto: 'Empresa de pintura (latas)',
    enunciado: 'Una distribuidora de materiales de construcción maneja **2.400 latas de pintura** por año.\n\n' +
               '- Costo por pedido: **$5.000**\n' +
               '- Costo de almacenamiento: **$600/lata/año**\n' +
               '- T = 1 año\n\n' +
               '**¿Cuál es el EOQ y cuántos pedidos se realizan por año?**',
    datos: { D: 2400, K: 5000, c1: 600, T: 1 },
    solucion: {
      q0_exacto: 200,
      q0_redondeado: 200,
      N: 12,
      CTE: 120000,
      paso_a_paso: 'q0 = sqrt((2 × 5000 × 2400) / (1 × 600)) = sqrt(24.000.000 / 600) = sqrt(40.000) = **200 unidades**\nN = D/q0 = 2400/200 = **12 pedidos/año**'
    },
    pista: 'Con D=2400, K=5000, c1=600: el numerador es 2×5000×2400 = 24.000.000. El denominador es 600. ¿Cuánto es 24.000.000/600?'
  },
  {
    id: 3,
    contexto: 'Depósito de tornillos (período trimestral)',
    enunciado: 'Un depósito maneja **800 unidades de tornillos** por trimestre (T = 0,25 años).\n\n' +
               '- Costo por orden: **$1.500**\n' +
               '- Costo de mantener: **$200/unidad/año**\n\n' +
               '**¿Cuál es el lote óptimo (q₀) y cuál es el tiempo entre pedidos en días?**',
    datos: { D: 800, K: 1500, c1: 200, T: 0.25 },
    solucion: {
      q0_exacto: 173.2,
      q0_redondeado: 173,
      t_dias: 20,
      CTE: 8660,
      paso_a_paso: 'q0 = sqrt((2 × 1500 × 800) / (0,25 × 200)) = sqrt(2.400.000 / 50) = sqrt(48.000) ≈ 219... Espera, recalculando: sqrt((2×1500×800)/(0.25×200)) = sqrt(2400000/50) = sqrt(48000) ≈ **219 unidades**. t = T/N = 0,25/(800/219) ≈ **0,068 años ≈ 25 días**'
    },
    pista: 'Atención: T=0,25 (un trimestre, no un año). El denominador de la fórmula es T×c1 = 0,25 × 200 = 50'
  }
];

const ej = ejercicios[(num - 1) % ejercicios.length];

// Recalcular solución correcta
const D = ej.datos.D, K = ej.datos.K, c1 = ej.datos.c1, T = ej.datos.T;
const q0_real = Math.sqrt((2 * K * D) / (T * c1));
const q0_r = Math.round(q0_real);
const N_real = D / q0_real;
const t_real = T / N_real;
const CTE_real = (D/q0_real)*K + (q0_real/2)*T*c1;

return JSON.stringify({
  ejercicio_id: ej.id,
  contexto: ej.contexto,
  enunciado: ej.enunciado,
  datos: ej.datos,
  total_ejercicios: ejercicios.length,
  solucion_correcta: {
    q0_exacto: parseFloat(q0_real.toFixed(2)),
    q0_redondeado: q0_r,
    CTE: parseFloat(CTE_real.toFixed(2)),
    N: parseFloat(N_real.toFixed(2)),
    t_dias: Math.round(t_real * 365)
  },
  pista: ej.pista
});

// Herramienta: generar_grafico
// Genera gráfico EOQ usando QuickChart.io

let params;
try {
  params = JSON.parse(query);
} catch (e) {
  return 'Error al parsear parámetros para el gráfico.';
}

const D  = parseFloat(params.D);
const K  = parseFloat(params.K);
const c1 = parseFloat(params.c1);
const T  = parseFloat(params.T || 1);
const q0 = parseFloat(params.q0 || Math.sqrt((2 * K * D) / (T * c1)));

if ([D, K, c1, T, q0].some(v => isNaN(v) || v <= 0)) {
  return 'Error: parámetros inválidos para generar el gráfico.';
}

// Rango del gráfico: de 10% a 300% del EOQ
const qMin = Math.max(1, Math.round(q0 * 0.1));
const qMax = Math.round(q0 * 3);
const PUNTOS = 40;

const labels = [];
const dataCostoPedido = [];
const dataCostoMantener = [];
const dataCostoTotal = [];

for (let i = 0; i <= PUNTOS; i++) {
  const q = qMin + (qMax - qMin) * i / PUNTOS;
  labels.push(Math.round(q));
  dataCostoPedido.push(parseFloat(((D / q) * K).toFixed(2)));
  dataCostoMantener.push(parseFloat(((q / 2) * T * c1).toFixed(2)));
  dataCostoTotal.push(parseFloat((((D / q) * K) + ((q / 2) * T * c1)).toFixed(2)));
}

const CTE_min = parseFloat(((D / q0) * K + (q0 / 2) * T * c1).toFixed(2));

const chartConfig = {
  type: 'line',
  data: {
    labels: labels,
    datasets: [
      {
        label: 'Costo de Pedido',
        data: dataCostoPedido,
        borderColor: 'rgb(54, 162, 235)',
        backgroundColor: 'rgba(54, 162, 235, 0.05)',
        borderWidth: 2,
        fill: false,
        tension: 0.4,
        pointRadius: 0
      },
      {
        label: 'Costo de Mantenimiento',
        data: dataCostoMantener,
        borderColor: 'rgb(255, 99, 132)',
        backgroundColor: 'rgba(255, 99, 132, 0.05)',
        borderWidth: 2,
        fill: false,
        tension: 0.4,
        pointRadius: 0
      },
      {
        label: 'Costo Total (CTE)',
        data: dataCostoTotal,
        borderColor: 'rgb(40, 167, 69)',
        backgroundColor: 'rgba(40, 167, 69, 0.1)',
        borderWidth: 3,
        fill: false,
        tension: 0.4,
        pointRadius: 0
      }
    ]
  },
  options: {
    title: {
      display: true,
      text: 'Modelo EOQ - q0=' + Math.round(q0) + ' uds | CTE min=$' + CTE_min.toLocaleString(),
      fontSize: 14
    },
    legend: { position: 'top' },
    scales: {
      xAxes: [{
        scaleLabel: { display: true, labelString: 'Cantidad de Pedido (q)' }
      }],
      yAxes: [{
        scaleLabel: { display: true, labelString: 'Costo ($)' }
      }]
    }
  }
};

const configStr = JSON.stringify(chartConfig);
const chartUrl = 'https://quickchart.io/chart?w=750&h=420&c=' + encodeURIComponent(configStr);

return JSON.stringify({
  url_grafico: chartUrl,
  q0_redondeado: Math.round(q0),
  CTE_minimo: CTE_min,
  descripcion_curvas: [
    '🔵 Curva azul (Costo de Pedido): decrece hiperbólicamente cuando q aumenta. Pedidos más grandes = menos pedidos = menos costo de emisión.',
    '🔴 Curva roja (Costo de Mantenimiento): crece linealmente cuando q aumenta. Pedidos más grandes = más stock promedio = más costo de almacenamiento.',
    '🟢 Curva verde (Costo Total): tiene forma de U. El mínimo de esta curva es exactamente el EOQ (q₀=' + Math.round(q0) + ' unidades).',
    '📍 El punto de intersección entre la curva azul y la roja coincide con el mínimo del CTE, confirmando la fórmula de Wilson.'
  ],
  interpretacion: 'El gráfico demuestra visualmente por qué el EOQ es óptimo: cualquier cantidad mayor o menor que q₀=' + Math.round(q0) + ' unidades genera un costo total mayor a $' + CTE_min.toLocaleString() + '.'
});
